using System.Collections;
using UnityEngine;

/// <summary>
/// Abre o Menu de Pausa na secção "Formas" e toca a animação curta de
/// revelação de "form" no seu ramo da árvore das transformações (Tarefa #9:
/// "Quando um animal novo é desbloqueado, essa tela abre, e aparece a
/// animação do animal sendo revelado no ramo").
///
/// Não marca o animal como libertado nem o desbloqueia para jogar — usar em
/// conjunto com Action_FreeAnimal (RewardActions.cs), DEPOIS dessa acção, no
/// mesmo evento de diálogo.
/// </summary>
[System.Serializable]
public class Action_RevealAnimalForm : NpcAction
{
    public AnimalFormData form;

    public override IEnumerator Execute(NpcController npc)
    {
        FormsSectionUI.Instance?.PlayUnlockReveal(form);
        yield break;
    }
}
